VALUES
  ('fire-eq-tech-moex-00215', 'fire-eq-tech', 'fire-eq-tech-moex-113-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '為能有效排除火場中的濃煙，必須定期確保排煙設備之有效性，依據排煙設備檢修基準之要 求，進行排煙設備的相關檢查時，下列敘述何者錯誤？', '["排煙機啟動後，能連動吸煙口及排煙閘門開啟", "綜合檢查時，醫院等切換成緊急電源進行檢查有困難之場所，應使用常用電源進行檢查", "進行自動啟動裝置之性能檢查時，檢查方法為偵煙式探測器性能檢查，依照火警自動警報 設備之檢查要領進行，確認探測器動作後，能否連動排煙機啟動", "外觀檢查時，應注意有無室內裝修、增建改建及用途變更，並檢查排煙區劃之狀態"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:23+00:00", "source_pdf_sha1": "8e5d77f9140e", "answer_pdf_sha1": "7f4f9bce7de8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113050", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "113", "exam_name": "113年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00216', 'fire-eq-tech', 'fire-eq-tech-moex-113-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '對於緊急電源插座距離樓地板的裝設高度範圍，下列何者正確？', '["1.0公尺以上，1.5公尺以下", "0.8公尺以上，1.5公尺以下", "0.6公尺以上，1.5公尺以下", "0.5公尺以上，1.5公尺以下"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:23+00:00", "source_pdf_sha1": "8e5d77f9140e", "answer_pdf_sha1": "7f4f9bce7de8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113050", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "113", "exam_name": "113年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00217', 'fire-eq-tech', 'fire-eq-tech-moex-113-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '下列場所不得免設排煙設備？', '["建築物在第 10 層以下之地下層，其非居室部分，天花板及室內牆面，以耐燃一級材料裝 修，且除面向室外之開口外，以半小時以上防火時效之防火門窗等防火設備區劃者", "建築物在第10層以下之各樓層，其非居室部分，樓地板面積每100平方公尺以下，以防煙 壁區劃者", "機器製造工廠、儲放不燃性物品倉庫及其他類似用途建築物，且主要構造為不燃材料建造者", "設有二氧化碳或乾粉等滅火設備之場所"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:23+00:00", "source_pdf_sha1": "8e5d77f9140e", "answer_pdf_sha1": "7f4f9bce7de8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113050", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "113", "exam_name": "113年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00218', 'fire-eq-tech', 'fire-eq-tech-moex-113-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '工業廠房設置機械排煙設備，其中特別安全梯與緊急升降機間兼用排煙室，該區域排煙閘門 大小為6m2，並連接排煙管道時，不考慮溫度影響之因素，請問排煙風速（m/s）應達多少才 能符合其法令規定？', '["1", "0.5", "0.25", "0.1"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:23+00:00", "source_pdf_sha1": "8e5d77f9140e", "answer_pdf_sha1": "7f4f9bce7de8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113050", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "113", "exam_name": "113年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00219', 'fire-eq-tech', 'fire-eq-tech-moex-113-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依據現行出口標示燈及避難方向指示燈認可基準，對於內置型引導燈具相關試驗等標準，何 者錯誤？', '["內置型引導燈具有效亮燈時間：20分鐘以上或是60分鐘以上", "內置型引導燈具鎳鎘或鎳氫蓄電池之放電標準：將充足電之燈具，連續放電25或75分鐘 後，電池之端電壓不得少於標稱電壓之87.5%，且測此電壓時放電作業不得停止", "平均亮度試驗內緊急電源試驗之測試時間：為於執行常用電源之測試後，再依產品標示額 定充電時間完成後即予斷電，並於斷電後25或75分鐘後即實施試驗，並於10分鐘內測試 完畢", "內置型引導燈具緊急電源時間：應維持8分鐘以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:23+00:00", "source_pdf_sha1": "8e5d77f9140e", "answer_pdf_sha1": "7f4f9bce7de8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113050", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "113", "exam_name": "113年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00220', 'fire-eq-tech', 'fire-eq-tech-moex-113-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依據各類場所消防安全設備設置標準之規定，避難器具於開口部應保有必要開口面積，下列 敘述何者錯誤？', '["緩降機開口部高與寬的加總最小值為130公分", "救助袋開口部高與寬的加總最小值為130公分", "滑臺開口部高度為80公分以上，寬為滑臺最大寬度以上", "避難繩索開口部高與寬的加總最小值為130公分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:23+00:00", "source_pdf_sha1": "8e5d77f9140e", "answer_pdf_sha1": "7f4f9bce7de8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113050", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "113", "exam_name": "113年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00221', 'fire-eq-tech', 'fire-eq-tech-moex-113-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '醫療機構中的3樓，經容納病床數量、從業員工與相關區域之樓地板面積等相關條件評估後， 其收容人數為550人，該樓層在無減設、免設考量下，至少應設多少具避難器具？', '["2", "3", "5", "6"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:23+00:00", "source_pdf_sha1": "8e5d77f9140e", "answer_pdf_sha1": "7f4f9bce7de8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113050", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "113", "exam_name": "113年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
